INSERT INTO public.central_content (level_id, variant, content, order_index, version) VALUES ((SELECT id FROM public.levels WHERE slug = 'matematik-1'), 'a', 'Matematiska begrepp som är relevanta för karaktärsämnen och yrkesliv, till exempel proportionalitet, skala, Pythagoras sats, procent och andelar, indexmått, vinstmarginal, jämvikt, felmarginaler, symmetrier, vektorer, trigonometriska funktioner och matematiska begrepp som utvecklas under förskoleåldern.', 0, '2025-skolverket');
INSERT INTO public.central_content (level_id, variant, content, order_index, version) VALUES ((SELECT id FROM public.levels WHERE slug = 'matematik-1'), 'a', 'Beräkningsmetoder som är relevanta för karaktärsämnen och yrkesliv, till exempel uppskattningar, beräkningar på störningar eller mätfel, spill- och svinnberäkningar, överslagsräkning, avrundning, användning av kalkylprogram och metoder för kontrollberäkning.', 1, '2025-skolverket');
INSERT INTO public.central_content (level_id, variant, content, order_index, version) VALUES ((SELECT id FROM public.levels WHERE slug = 'matematik-1'), 'a', 'Hantering av formler som är relevanta för karaktärsämnen och yrkesliv.', 2, '2025-skolverket');
