INSERT INTO public.central_content (level_id, variant, content, order_index, version) VALUES ((SELECT id FROM public.levels WHERE slug = 'matematik-1'), 'a', 'Hjälpmedel och verktyg som är relevanta för att hantera matematik inom karaktärsämnen och yrkesliv, till exempel formulär, mallar, tumregler, föreskrifter, manualer, referensverk och handböcker.', 4, '2025-skolverket');
INSERT INTO public.central_content (level_id, variant, content, order_index, version) VALUES ((SELECT id FROM public.levels WHERE slug = 'matematik-1'), 'a', 'Hantering av algebraiska uttryck, inklusive att faktorisera och multiplicera uttryck.', 5, '2025-skolverket');
