INSERT INTO public.knowledge_requirements (level_id, variant, grade_level, description, order_index) VALUES ((SELECT id FROM public.levels WHERE slug = 'matematik-2'), 'a', 'E', 'Eleven beskriver grundläggande begrepp och samband mellan begrepp samt använder dem med tillfredsställande säkerhet. Eleven hanterar grundläggande procedurer och löser uppgifter av standardkaraktär med tillfredsställande säkerhet, både utan och med digitala verktyg. Eleven löser enkla problem inom kursens olika områden. Eleven bedömer resultatens rimlighet. Eleven tillämpar och formulerar matematiska modeller i enkla uppgifter. Eleven för delvis underbyggda matematiska resonemang och följer enkla matematiska resonemang. Eleven uttrycker sig med matematiska symboler och andra representationer på ett i huvudsak fungerande sätt.', 0);
