INSERT INTO public.knowledge_requirements (level_id, variant, grade_level, description, order_index) VALUES ((SELECT id FROM public.levels WHERE slug = 'matematik-3'), 'b', 'E', 'Eleven beskriver grundläggande begrepp och samband mellan begrepp samt använder dem med tillfredsställande säkerhet. Eleven hanterar grundläggande procedurer och löser uppgifter av standardkaraktär med tillfredsställande säkerhet, både utan och med digitala verktyg. Eleven löser enkla problem inom kursens olika områden. Eleven bedömer resultatens rimlighet. Eleven tillämpar och formulerar matematiska modeller i enkla uppgifter, samt utvärderar matematiska modellers egenskaper och begränsningar. Eleven för delvis underbyggda matematiska resonemang och följer enkla matematiska resonemang. Eleven uttrycker sig med matematiska symboler och andra representationer på ett i huvudsak fungerande sätt.', 0);
INSERT INTO public.knowledge_requirements (level_id, variant, grade_level, description, order_index) VALUES ((SELECT id FROM public.levels WHERE slug = 'matematik-3'), 'b', 'C', 'Eleven beskriver ett omfattande antal begrepp och samband mellan begrepp samt använder dem med god säkerhet. Eleven hanterar ett omfattande antal procedurer och löser uppgifter av standardkaraktär med god säkerhet, både utan och med digitala verktyg. Eleven hanterar avancerade uttryck med god säkerhet. Eleven löser relativt komplexa problem inom kursens olika områden. Eleven bedömer resultatens rimlighet. Eleven tillämpar och formulerar matematiska modeller i relativt komplexa uppgifter, samt utvärderar matematiska modellers egenskaper och begränsningar. Eleven för relativt väl underbyggda matematiska resonemang , genomför enkla bevis och följer relativt avancerade matematiska resonemang. Eleven uttrycker sig med matematiska symboler och andra representationer på ett till stor del tydligt och korrekt sätt.', 1);
INSERT INTO public.knowledge_requirements (level_id, variant, grade_level, description, order_index) VALUES ((SELECT id FROM public.levels WHERE slug = 'matematik-3'), 'b', 'A', 'Eleven beskriver ett omfattande antal begrepp och samband mellan begrepp samt använder dem med mycket god säkerhet. Eleven hanterar ett omfattande antal procedurer och löser uppgifter av standardkaraktär med mycket god säkerhet, både utan och med digitala verktyg. Eleven hanterar avancerade uttryck med mycket god säkerhet. Eleven löser komplexa problem inom kursens olika områden. Eleven bedömer resultatens rimlighet. Eleven tillämpar och formulerar matematiska modeller i komplexa uppgifter, samt utvärderar matematiska modellers egenskaper och begränsningar. Eleven för väl underbyggda matematiska resonemang , genomför bevis och följer avancerade matematiska resonemang. Eleven uttrycker sig med matematiska symboler och andra representationer på ett tydligt och korrekt sätt. <a', 2);
